public static <T> T isA(Class<T> clazz) {
        return reportMatcher(new InstanceOf(clazz)).<T>returnFor(clazz);
    }

public static <T> T eq(T value) {
        Class<?> cls = (value == null) ? Object.class : value.getClass();
        return reportMatcher(new Equals(value)).<T>returnFor((Class<T>) cls);
    }

public static <T> T same(T value) {
        Class<?> cls = (value == null) ? Object.class : value.getClass();
        return reportMatcher(new Same(value)).<T>returnFor((Class<T>) cls);
    }
